$(document).ready(function() {
        var baseUrl = window.location.origin;
        let retrive_data = baseUrl+'/cat';
        let edit_category = baseUrl+'/master/category/edit_category';
      
        // Initialize DataTable
        $('#view_category').DataTable({
            processing: true,
            serverSide: true,
            searching: true,
            scrollY: 500,
            scrollX: true,
            scrollCollapse: true,
            
            columnDefs: [{
                "defaultContent": "-",
                "targets": 0,
                "render": function (data, type, row, meta) {
                  // Return the serial number (row index + 1)
                  return meta.row + 1;
                }
              }],
            ajax: {
                url: retrive_data,
            },

            "columns": [
              { "data": null }, // This column will be used for serial numbers
                 
                { 
                  "data": "name",
                },
                { 
                  title: 'Status',
                  render: function(data, type, full) {
                      if (full.status === 1) {
                        return '<span class="badge badge-pill badge-success">Active</span>';
                    } else {
                        return '<span class="status-inactive">Inactive</span>';
                    }     
                  }
              },
              { 
                title: 'Action',
                render: function(data, type, full) {
                    return `
                    <a href='edit_category/${full.id}'><i class="ti-pencil-alt"></i></a>
                     `;      
                }
            }

            ]
        });
});